import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import './buy.css';

function Buy() {
    const [arr_orders, setArrOrders] = useState([]);
    const [loading, setLoading] = useState(true);
    const currentUser = useSelector((state) => state.user.currentUser);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchOrders = async () => {
            // אם אין משתמש או שזה אורח, אין טעם לפנות לשרת
            if (!currentUser || currentUser.customerName === "guest") {
                setLoading(false);
                return;
            }

            try {
                const response = await fetch(`http://localhost:8080/api/shoppingApi/getShoppingByCustomerId/${currentUser.pin}`);
                const data = await response.json();
                setArrOrders(data);
            } catch (error) {
                console.error("שגיאה בשליפה", error);
            } finally {
                setLoading(false);
            }
        };

        fetchOrders();
    }, [currentUser]);

    // בדיקה: האם המשתמש מחובר?
    if (!currentUser || currentUser.customerName === "guest") {
        return (
            <div className="orders-container">
                <div className="no-user-logged">
                    <h2>אופס! אינך מחובר למערכת</h2>
                    <p>כדי לצפות בהיסטוריית ההזמנות שלך, עליך להתחבר לחשבון.</p>
                    <button className="login-redirect-btn" onClick={() => navigate('/logIn')}>
                        התחבר עכשיו
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="orders-container">
            <h1 className="title">היסטוריית הקניות שלי</h1>

            {loading ? (
                <div className="loader-area">
                    <p className="status-msg">טוען נתונים מהמערכת...</p>
                </div>
            ) : arr_orders.length > 0 ? (
                <div className="orders-list">
                    {arr_orders.map((order) => (
                        <div key={order._id} className="order-card">
                            <div className="order-header">
                                <span className="order-id">קנייה מס' {order._id.slice(-6)}</span>
                            </div>

                            <div className="order-body">
                                <h4 className="products-title">פירוט מוצרים:</h4>
                                <ul className="robots-list">
                                    {order.robots && order.robots.map((robot, index) => (
                                        <li key={index} className="order-item-row">
                                            <div className="item-right-group">
                                                <div className="item-img-container">
                                                    {robot.img && <img src={"http://localhost:8080/" + robot.img} alt={robot.robotName} />}
                                                </div>
                                                <div className="item-text-content">
                                                    <span className="item-name">{robot.robotName}</span>
                                                    <span className="item-price-each">{robot.price} ₪ ליחידה</span>
                                                </div>
                                            </div>
                                            <div className="item-left-group">
                                                <span className="qty-text">כמות: {robot.count}</span>
                                            </div>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                            <div className="order-footer">
                                <div className="total-price-container">
                                    <span className="total-amount">סה"כ: {order.sum} ₪</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="no-data">
                    <p>לא נמצאו רכישות קודמות בחשבון זה.</p>
                </div>
            )}
        </div>
    );
}

export default Buy;
